<?php require __DIR__.'/includes/bootstrap.php';$num=trim($_GET['order']??'');$s=db()->prepare('SELECT o.*,b.name AS booth_name,b.slug AS booth_slug FROM booth_orders o JOIN booths b ON b.id=o.booth_id WHERE o.order_number=?');$s->execute([$num]);$o=$s->fetch();if(!$o){http_response_code(404);exit('Order not found.');}app_header('Order Confirmation');?>
